function isValid(bytes32 hash, bytes memory sig) returns (bool) {
    bytes32 typeHash = keccak256(
        abi.encodePacked("TypedDataSign(", contentsName, " contents,string name,...)", contentsType)
    );
    bytes32 structHash = keccak256(abi.encode(typeHash, contents, hashedName, ...));
    bytes32 finalHash = keccak256(abi.encodePacked("\x19\x01", appDomainSep, structHash));
    return ECDSA.recover(finalHash, sig) == owner();
}

